#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX_K 1000000000
#define MAX_D 7

long long dp[MAX_K + 1][MAX_D + 1][MAX_D + 1];

long long solve(int k, int d) {
    if (k == 0) return 1;
    if (dp[k][0][0] != -1) return dp[k][0][0];
    long long ans = 0;
    for (int i = 0; i <= d; i++) {
        for (int j = 0; j <= d; j++) {
            if (i + j <= k) {
                ans = (ans + solve(k - i - j, d)) % MOD;
            }
        }
    }
    return dp[k][0][0] = ans;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int d, k;
        scanf("%d %d", &d, &k);
        for (int i = 0; i <= k; i++) {
            for (int j = 0; j <= d; j++) {
                for (int l = 0; l <= d; l++) {
                    dp[i][j][l] = -1;
                }
            }
        }
        printf("%lld\n", solve(k, d));
    }
    return 0;
}

