import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.StringTokenizer;

public class Main {
    static final int MOD = 1000000007;
    static final int MAX_K = 1000000000;
    static final int MAX_D = 7;
    static long[][][] dp = new long[MAX_K + 1][MAX_D + 1][MAX_D + 1];

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);
        int t = Integer.parseInt(br.readLine());
        while (t-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int d = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            for (int i = 0; i <= k; i++) {
                for (int j = 0; j <= d; j++) {
                    for (int l = 0; l <= d; l++) {
                        dp[i][j][l] = -1;
                    }
                }
            }
            pw.println(solve(k, d));
        }
        pw.close();
    }

    static long solve(int k, int d) {
        if (k == 0) return 1;
        if (dp[k][0][0] != -1) return dp[k][0][0];
        long ans = 0;
        for (int i = 0; i <= d; i++) {
            for (int j = 0; j <= d; j++) {
                if (i + j <= k) {
                    ans = (ans + solve(k - i - j, d)) % MOD;
                }
            }
        }
        return dp[k][0][0] = ans;
    }
}

